"""Resolve legacy vs domain-driven mode from a target repo's ``.rebaseai/config.yaml``."""

from __future__ import annotations

import base64
import logging
import re
from pathlib import Path
from typing import Literal
from urllib.parse import urlparse

import httpx

RepoMode = Literal["legacy", "domain-driven"]

_CONFIG_REL_PATH = ".rebaseai/config.yaml"
_DOMAIN_MAP_REL_PATH = "design/domain-map.md"
_MODE_LINE = re.compile(
    r"^mode:\s*(?:['\"]?)(legacy|domain-driven)(?:['\"]?)\s*(?:#.*)?$",
    re.MULTILINE | re.IGNORECASE,
)

logger = logging.getLogger(__name__)


def parse_github_repo_slug(source_repo: str) -> tuple[str, str]:
    """Return ``(owner, repo)`` from an HTTPS or SSH clone URL."""
    raw = (source_repo or "").strip().rstrip("/")
    if not raw:
        raise ValueError("source_repo is required")

    if raw.startswith("git@"):
        # git@github.com:owner/repo.git
        _, _, path = raw.partition(":")
        slug = path.removesuffix(".git")
    else:
        parsed = urlparse(raw)
        path = parsed.path.lstrip("/")
        if path.endswith(".git"):
            path = path[:-4]
        slug = path

    if "/" not in slug:
        raise ValueError(f"could not parse owner/repo from source_repo: {source_repo!r}")
    owner, repo = slug.split("/", 1)
    if not owner or not repo:
        raise ValueError(f"could not parse owner/repo from source_repo: {source_repo!r}")
    return owner, repo


def resolve_repo_mode_from_config_content(content: str | None) -> RepoMode:
    """Parse ``mode`` from YAML text; absent or invalid values default to ``legacy``."""
    if not content or not content.strip():
        logger.info("repo mode: no config content; defaulting to legacy")
        return "legacy"
    match = _MODE_LINE.search(content)
    if not match:
        logger.info("repo mode: missing or invalid mode key; defaulting to legacy")
        return "legacy"
    mode = match.group(1).lower()
    if mode == "domain-driven":
        return "domain-driven"
    if mode != "legacy":
        logger.info("repo mode: unrecognized mode %r; defaulting to legacy", mode)
    return "legacy"


def resolve_repo_mode_from_path(config_path: Path) -> RepoMode:
    """Read mode from a local ``.rebaseai/config.yaml`` path."""
    if not config_path.is_file():
        logger.info("repo mode: %s not found; defaulting to legacy", config_path)
        return "legacy"
    return resolve_repo_mode_from_config_content(
        config_path.read_text(encoding="utf-8"),
    )


def resolve_repo_mode_from_source_dir(source_dir: Path) -> RepoMode:
    """Read mode from ``source/.rebaseai/config.yaml`` after clone."""
    return resolve_repo_mode_from_path(source_dir / _CONFIG_REL_PATH)


def _github_headers(token: str) -> dict[str, str]:
    return {
        "Authorization": f"Bearer {token}",
        "Accept": "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28",
    }


def fetch_github_file_content(
    owner: str,
    repo: str,
    path: str,
    *,
    token: str,
    ref: str | None = None,
) -> str | None:
    """Fetch a single file via the GitHub contents API; ``None`` when absent."""
    url = f"https://api.github.com/repos/{owner}/{repo}/contents/{path}"
    params = {"ref": ref} if ref else None
    response = httpx.get(
        url,
        headers=_github_headers(token),
        params=params,
        timeout=30.0,
    )
    if response.status_code == 404:
        return None
    response.raise_for_status()
    payload = response.json()
    if not isinstance(payload, dict):
        return None
    encoding = payload.get("encoding")
    content = payload.get("content")
    if not isinstance(content, str):
        return None
    if encoding == "base64":
        return base64.b64decode(content).decode("utf-8")
    return content


def resolve_repo_mode_from_github(
    owner: str,
    repo: str,
    *,
    token: str,
    ref: str | None = None,
) -> RepoMode:
    """Resolve mode via GitHub contents API (pre-clone dispatch)."""
    content = fetch_github_file_content(
        owner,
        repo,
        _CONFIG_REL_PATH,
        token=token,
        ref=ref,
    )
    return resolve_repo_mode_from_config_content(content)


def resolve_repo_mode(
    source_repo: str,
    *,
    token: str,
    ref: str | None = None,
) -> RepoMode:
    """Resolve repo mode from ``source_repo`` using the GitHub contents API."""
    owner, repo = parse_github_repo_slug(source_repo)
    return resolve_repo_mode_from_github(owner, repo, token=token, ref=ref)


def assert_repo_mode_matches(*, dispatched: RepoMode, actual: RepoMode) -> None:
    """Fail fast when dispatch-time and post-clone mode disagree."""
    if dispatched != actual:
        raise ValueError(
            f"repo mode mismatch: dispatched={dispatched!r} actual={actual!r}",
        )


def domain_map_exists_on_github(
    owner: str,
    repo: str,
    *,
    token: str,
    ref: str,
) -> bool:
    """Return whether ``design/domain-map.md`` exists on ``ref``."""
    return (
        fetch_github_file_content(
            owner,
            repo,
            _DOMAIN_MAP_REL_PATH,
            token=token,
            ref=ref,
        )
        is not None
    )

"""Workflow pack path resolution for domain-driven design workflows."""

from __future__ import annotations

from pathlib import Path

DOMAIN_BOOTSTRAP_WORKFLOW_DIR_ENV = "DOMAIN_BOOTSTRAP_WORKFLOW_DIR"
DOMAIN_ISSUE_WORKFLOW_DIR_ENV = "DOMAIN_ISSUE_WORKFLOW_DIR"

_WORKFLOWS_ROOT = Path(__file__).resolve().parent.parent.parent / "workflows"


def default_bootstrap_pack_root() -> Path:
    return _WORKFLOWS_ROOT / "domain-bootstrap"


def default_issue_pack_root() -> Path:
    return _WORKFLOWS_ROOT / "domain-issue"


def resolve_bootstrap_pack_root(override_dir: str) -> Path:
    raw = override_dir.strip()
    return Path(raw).expanduser() if raw else default_bootstrap_pack_root()


def resolve_issue_pack_root(override_dir: str) -> Path:
    raw = override_dir.strip()
    return Path(raw).expanduser() if raw else default_issue_pack_root()


def workflow_yaml_path(pack_root: Path) -> Path:
    return pack_root / "workflow.yaml"

"""AgentOS workflow wrappers for domain-driven design (bootstrap + per-issue)."""

from __future__ import annotations

import json
from typing import Any

from agno.db.postgres import PostgresDb
from agno.workflow.workflow import Workflow
from pydantic import BaseModel, Field

from agents.domain_driven.runner import (
    DomainBootstrapRunRequest,
    DomainDrivenRunner,
    DomainIssueRunRequest,
)
from agno_platform.typing.agno_workflow import Step, StepInput, StepOutput


class DomainBootstrapInput(BaseModel):
    """Input contract for the domain-bootstrap workflow."""

    source_repo: str = Field(
        ...,
        description="Git clone URL for the repository under design (HTTPS or SSH).",
    )
    plan_text: str = Field(
        ...,
        description="Project plan markdown (verbatim).",
    )
    start_branch: str = Field(
        ...,
        description="Base branch to create domain-design/bootstrap from.",
    )


class DomainIssueInput(BaseModel):
    """Input contract for the domain-issue workflow."""

    source_repo: str = Field(
        ...,
        description="Git clone URL for the repository under design (HTTPS or SSH).",
    )
    issue_ref: str = Field(
        ...,
        description="GitHub issue number or issue URL.",
    )
    start_branch: str = Field(
        ...,
        description="Base branch for the design PR.",
    )


def _parse_json_message(raw: str) -> dict[str, Any] | None:
    text = raw.strip()
    if not text.startswith("{"):
        return None
    try:
        parsed = json.loads(text)
    except json.JSONDecodeError:
        return None
    return parsed if isinstance(parsed, dict) else None


async def execute_domain_bootstrap(
    params: DomainBootstrapInput,
) -> tuple[dict[str, Any], bool, str | None]:
    """Run domain-bootstrap flow; return (content, success, error detail)."""
    try:
        runner = DomainDrivenRunner.from_env()
        result = await runner.run_bootstrap_async(
            DomainBootstrapRunRequest(
                source_repo=params.source_repo,
                plan_text=params.plan_text,
                start_branch=params.start_branch,
            )
        )
    except Exception as exc:  # noqa: BLE001
        return (
            {"domain_bootstrap": {"ok": False, "error": str(exc)}},
            False,
            str(exc),
        )

    body = {
        "domain_bootstrap": {
            "ok": result.exit_code == 0,
            "exit_code": result.exit_code,
            "pr_url": result.pr_url,
            "run_dir": str(result.run_dir),
            "log_path": str(result.log_path),
            "flow_log_tail": result.flow_log_tail,
        }
    }
    if result.exit_code != 0:
        detail = f"flow exited with code {result.exit_code}"
        if result.flow_log_tail:
            detail = f"{detail}\n{result.flow_log_tail}"
        return body, False, detail
    return body, True, None


async def execute_domain_issue(
    params: DomainIssueInput,
) -> tuple[dict[str, Any], bool, str | None]:
    """Run domain-issue flow; return (content, success, error detail)."""
    try:
        runner = DomainDrivenRunner.from_env()
        result = await runner.run_issue_async(
            DomainIssueRunRequest(
                source_repo=params.source_repo,
                issue_ref=params.issue_ref,
                start_branch=params.start_branch,
            )
        )
    except Exception as exc:  # noqa: BLE001
        return (
            {"domain_issue": {"ok": False, "error": str(exc)}},
            False,
            str(exc),
        )

    body = {
        "domain_issue": {
            "ok": result.exit_code == 0,
            "exit_code": result.exit_code,
            "pr_url": result.pr_url,
            "run_dir": str(result.run_dir),
            "log_path": str(result.log_path),
            "flow_log_tail": result.flow_log_tail,
        }
    }
    if result.exit_code != 0:
        detail = f"flow exited with code {result.exit_code}"
        if result.flow_log_tail:
            detail = f"{detail}\n{result.flow_log_tail}"
        return body, False, detail
    return body, True, None


async def run_domain_bootstrap(step_input: StepInput) -> StepOutput:
    try:
        if isinstance(step_input.input, DomainBootstrapInput):
            params = step_input.input
        elif isinstance(step_input.input, dict):
            params = DomainBootstrapInput.model_validate(step_input.input)
        else:
            raise ValueError(f"unsupported workflow input type: {type(step_input.input).__name__}")
    except Exception as exc:  # noqa: BLE001
        return StepOutput(
            content={"domain_bootstrap": {"ok": False, "error": str(exc)}},
            success=False,
            error=str(exc),
        )

    body, success, error = await execute_domain_bootstrap(params)
    return StepOutput(content=body, success=success, error=error)


async def run_domain_issue(step_input: StepInput) -> StepOutput:
    try:
        if isinstance(step_input.input, DomainIssueInput):
            params = step_input.input
        elif isinstance(step_input.input, dict):
            params = DomainIssueInput.model_validate(step_input.input)
        else:
            raise ValueError(f"unsupported workflow input type: {type(step_input.input).__name__}")
    except Exception as exc:  # noqa: BLE001
        return StepOutput(
            content={"domain_issue": {"ok": False, "error": str(exc)}},
            success=False,
            error=str(exc),
        )

    body, success, error = await execute_domain_issue(params)
    return StepOutput(content=body, success=success, error=error)


DOMAIN_DRIVEN_REGISTRY_SCHEMAS: list[type[BaseModel]] = [DomainBootstrapInput, DomainIssueInput]
DOMAIN_DRIVEN_REGISTRY_FUNCTIONS = [run_domain_bootstrap, run_domain_issue]


def build_domain_bootstrap_workflow(db: PostgresDb) -> Workflow:
    return Workflow(
        id="domain-bootstrap",
        name="Domain bootstrap",
        description="Carve domains from a project plan and open a merged design PR.",
        db=db,
        input_schema=DomainBootstrapInput,
        steps=[
            Step(
                name="run_domain_bootstrap",
                description="Run domain bootstrap design workflow; return pull request URL.",
                executor=run_domain_bootstrap,
            ),
        ],
    )


def build_domain_issue_workflow(db: PostgresDb) -> Workflow:
    return Workflow(
        id="domain-issue",
        name="Domain issue design",
        description="Route an issue to affected domains and open a merged design PR.",
        db=db,
        input_schema=DomainIssueInput,
        steps=[
            Step(
                name="run_domain_issue",
                description="Run per-issue domain design workflow; return pull request URL.",
                executor=run_domain_issue,
            ),
        ],
    )

