"""Upload domain-driven prompt files from ``domain-driven/prompts/`` to Langfuse.

Run from repo root with LANGFUSE_* set (e.g. via .env):

    uv run python scripts/langfuse_upload_domain_driven_prompts.py
"""

from __future__ import annotations

import os
import re
import sys
from pathlib import Path

from langfuse import Langfuse

_REPO_ROOT = Path(__file__).resolve().parents[1]
_PROMPTS_DIR = _REPO_ROOT / "domain-driven" / "prompts"

_HEADER_RE = re.compile(r"^<!--.*?-->\s*", re.DOTALL)


def _load_langfuse_env() -> None:
    env_path = _REPO_ROOT / ".env"
    if not env_path.exists():
        return
    for line in env_path.read_text().splitlines():
        line = line.strip()
        if not line or line.startswith("#") or "=" not in line:
            continue
        key, _, value = line.partition("=")
        key = key.strip()
        if key.startswith("LANGFUSE_") and key not in os.environ:
            os.environ[key] = value.strip().strip('"').strip("'")


def _client() -> Langfuse:
    _load_langfuse_env()
    for required in ("LANGFUSE_PUBLIC_KEY", "LANGFUSE_SECRET_KEY", "LANGFUSE_BASE_URL"):
        if not os.environ.get(required):
            sys.exit(f"Missing {required}")
    return Langfuse(
        public_key=os.environ["LANGFUSE_PUBLIC_KEY"],
        secret_key=os.environ["LANGFUSE_SECRET_KEY"],
        host=os.environ["LANGFUSE_BASE_URL"].rstrip("/"),
    )


def _label() -> str:
    return os.environ.get("LANGFUSE_PROMPT_LABEL", "production").strip() or "production"


def _strip_header(body: str) -> str:
    return _HEADER_RE.sub("", body, count=1).strip()


def _read_prompt(path: Path) -> str:
    return _strip_header(path.read_text(encoding="utf-8"))


_PROMPT_FILES: list[tuple[str, str]] = [
    ("_architecture.md", "domain-driven/_architecture"),
    ("_engineering-stance.md", "domain-driven/_engineering-stance"),
    ("domain-architect.md", "domain-driven/architect"),
    ("domain-designer.md", "domain-driven/domain-designer"),
    ("coder.md", "domain-driven/coder"),
]


def main() -> None:
    client = _client()
    label = _label()
    for filename, langfuse_name in _PROMPT_FILES:
        path = _PROMPTS_DIR / filename
        if not path.is_file():
            sys.exit(f"Missing prompt file: {path}")
        body = _read_prompt(path)
        print(f"Uploading {langfuse_name} ({len(body)} chars) label={label}")
        client.create_prompt(
            name=langfuse_name,
            prompt=body,
            labels=[label],
            type="text",
            commit_message=f"Upload domain-driven prompt from {filename}",
        )
    print("Done.")


if __name__ == "__main__":
    main()

"""Unit tests for domain-driven repo mode resolution."""

from __future__ import annotations

from pathlib import Path

import httpx
import pytest
import respx

from agents.domain_driven.repo_mode import (
    assert_repo_mode_matches,
    parse_github_repo_slug,
    resolve_repo_mode_from_config_content,
    resolve_repo_mode_from_github,
    resolve_repo_mode_from_path,
)


@pytest.mark.parametrize(
    ("content", "expected"),
    [
        (None, "legacy"),
        ("", "legacy"),
        ("mode: legacy\n", "legacy"),
        ("mode: domain-driven\n", "domain-driven"),
        ("mode: 'domain-driven'\n", "domain-driven"),
        ("mode: unknown\n", "legacy"),
    ],
)
def test_resolve_repo_mode_from_config_content(content: str | None, expected: str) -> None:
    assert resolve_repo_mode_from_config_content(content) == expected


def test_parse_github_repo_slug_accepts_https_and_ssh() -> None:
    assert parse_github_repo_slug("https://github.com/o/r.git") == ("o", "r")
    assert parse_github_repo_slug("git@github.com:o/r.git") == ("o", "r")


def test_assert_repo_mode_matches_raises_on_mismatch() -> None:
    with pytest.raises(ValueError, match="repo mode mismatch"):
        assert_repo_mode_matches(dispatched="legacy", actual="domain-driven")


def test_resolve_repo_mode_from_path(tmp_path: Path) -> None:
    config = tmp_path / ".rebaseai" / "config.yaml"
    config.parent.mkdir(parents=True)
    config.write_text("mode: domain-driven\n", encoding="utf-8")
    assert resolve_repo_mode_from_path(config) == "domain-driven"


@respx.mock
def test_resolve_repo_mode_from_github_defaults_when_missing() -> None:
    respx.get("https://api.github.com/repos/o/r/contents/.rebaseai/config.yaml").respond(
        404,
    )
    assert resolve_repo_mode_from_github("o", "r", token="tok") == "legacy"


@respx.mock
def test_resolve_repo_mode_from_github_reads_config() -> None:
    import base64

    body = base64.b64encode(b"mode: domain-driven\n").decode("ascii")
    respx.get("https://api.github.com/repos/o/r/contents/.rebaseai/config.yaml").respond(
        200,
        json={"encoding": "base64", "content": body},
    )
    assert resolve_repo_mode_from_github("o", "r", token="tok") == "domain-driven"


@respx.mock
def test_resolve_repo_mode_from_github_propagates_http_errors() -> None:
    respx.get("https://api.github.com/repos/o/r/contents/.rebaseai/config.yaml").respond(
        500,
    )
    with pytest.raises(httpx.HTTPStatusError):
        resolve_repo_mode_from_github("o", "r", token="tok")

